import requests

def get_all_user_messages():
    channels = {"function": "get_channels", "parameters": {}}
    response = requests.post("http://localhost:5000/", json=channels)
    data = response.json()
    user_messages = {}
    for channel in data:
        messages = {"function": "read_channel_messages", "parameters": {"channel": channel}}
        response = requests.post("http://localhost:5000/", json=messages)
        data = response.json()
        for message in data:
            sender = message["sender"]
            if sender in user_messages:
                user_messages[sender] += 1
            else:
                user_messages[sender] = 1
    sorted_users = sorted(user_messages.items(), key=lambda x: (-x[1], x[0]))
    for i, (user, count) in enumerate(sorted_users):
        print(f"User {user} has sent {count} messages and is the {i+1} most active user.")

get_all_user_messages()
